item.description:
この前、イラストを描いたやつをtarot-cardに追加したいなって思って、現在の仕組は、以下のようなscriptでcardを生成し、その情報を記述したjsonをvueでimportしてたんですが、毎回buildするのが面倒だと思ったので、jsonの更新のみで対応することにしました。
この程度のことはブログに書こうか迷いましたが、どんな些細なことでも、できる限り書いてく方針なので。
#!/bin/zsh d=${0:a:h} dd=${0:a:h:h} n=`cat $d/static/json/tarot.json|jq &#34;length&#34;` n=`expr $n - 1` bg=$dd/static/img/tarot_bg.png br=$dd/static/img/tarot_br.png font=&#34;/System/Library/Font/ToppanBunkyuGothicPr6N.ttc&#34; for ((i=0;i&lt;=$n;i++)) do p=`cat $d/static/json/tarot.json|jq -r &#34;.[$i].p&#34;` h=`cat $d/static/json/tarot.json|jq -r &#34;.[$i].h&#34;` s=`cat $d/static/json/tarot.json|jq -r &#34;.[$i].src&#34;` s=$dd/static/img/yui_$s.png o=$dd/content`cat $d/static/json/tarot.json|jq -r &#34;.[$i].file&#34;`.png echo &#34;$s -&gt; $o&#34; composite -gravity north -geometry +0+160 -compose over $s $bg $o.back composite -gravity north -geometry +0+0 -compose over $br $o.back $o rm $o.back if [ `echo $h|wc -m` -eq 2 ];then mogrify -font &#34;$font&#34; -fill white -pointsize 200 -annotate +930+2570 &#34;$h&#34; $o else mogrify -font &#34;$font&#34; -fill white -pointsize 200 -annotate +830+2570 &#34;$h&#34; $o fi squoosh-cli --webp &#39;{&#34;quality&#34;:100}&#39; -d $dd/content/ai/tarot/ --resize &#39;{width:400,height:550}&#39; $o done s=$dd/static/img/tarot.
